import React, { useState } from 'react';

const COMMON_SKILLS = [
  'Python','JavaScript','Java','SQL','React','Machine Learning',
  'Deep Learning','TensorFlow','AWS','Docker','Node.js','MongoDB',
  'PostgreSQL','Data Analysis','NLP','Statistics','Kubernetes','Git',
];

const s = {
  container: { },
  pills: { display: 'flex', flexWrap: 'wrap', gap: 6, marginBottom: 10 },
  pill: (active) => ({
    padding: '5px 12px',
    borderRadius: 20,
    border: `1px solid ${active ? '#2563eb' : '#d1d5db'}`,
    background: active ? '#2563eb' : '#fff',
    color: active ? '#fff' : '#374151',
    fontSize: 12,
    fontWeight: 500,
    cursor: 'pointer',
    transition: 'all 0.15s',
  }),
  addRow: { display: 'flex', gap: 6, marginTop: 8 },
  input: {
    flex: 1,
    padding: '7px 12px',
    border: '1px solid #d1d5db',
    borderRadius: 6,
    fontSize: 13,
    outline: 'none',
  },
  addBtn: {
    padding: '7px 16px',
    background: '#2563eb',
    color: '#fff',
    border: 'none',
    borderRadius: 6,
    fontSize: 13,
    fontWeight: 500,
    cursor: 'pointer',
  },
  selected: {
    marginTop: 12,
    padding: '10px 14px',
    background: '#eff6ff',
    borderRadius: 6,
    fontSize: 12,
    color: '#1d4ed8',
  },
};

export default function SkillSelector({ selected, setSelected }) {
  const [custom, setCustom] = useState('');

  const toggle = (skill) => {
    setSelected(prev =>
      prev.includes(skill) ? prev.filter(s => s !== skill) : [...prev, skill]
    );
  };

  const addCustom = () => {
    const s = custom.trim();
    if (s && !selected.includes(s)) {
      setSelected(prev => [...prev, s]);
    }
    setCustom('');
  };

  return (
    <div style={s.container}>
      <div style={s.pills}>
        {COMMON_SKILLS.map(skill => (
          <button key={skill} style={s.pill(selected.includes(skill))} onClick={() => toggle(skill)}>
            {skill}
          </button>
        ))}
      </div>
      <div style={s.addRow}>
        <input
          style={s.input}
          placeholder="Add custom skill..."
          value={custom}
          onChange={e => setCustom(e.target.value)}
          onKeyDown={e => e.key === 'Enter' && addCustom()}
        />
        <button style={s.addBtn} onClick={addCustom}>+ Add</button>
      </div>
      {selected.length > 0 && (
        <div style={s.selected}>
          <strong>Required ({selected.length}):</strong> {selected.join(', ')}
        </div>
      )}
    </div>
  );
}
